import{_ as t,o,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"95A. Right To Disconnect Supplementary Roster","description":"","frontmatter":{"title":"95A. Right To Disconnect Supplementary Roster","eba":"Mental Health Services 2024-2028","topics":["leave","hours","rosters","right-to-disconnect"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/95A-right-to-disconnect-supplementary-roster.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/95A-right-to-disconnect-supplementary-roster.md"}'),s={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/95A-right-to-disconnect-supplementary-roster.md"};function a(i,e,l,p,c,h){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_95a-right-to-disconnect-supplementary-roster" tabindex="-1">95A. Right To Disconnect Supplementary Roster <a class="header-anchor" href="#_95a-right-to-disconnect-supplementary-roster" aria-label="Permalink to &quot;95A. Right To Disconnect Supplementary Roster&quot;">​</a></h1><p>This clause is additional to <a href="/eba/ebas/mental-health/common-terms/allowances/36-right-to-disconnect.html">clause 36</a> (Right to Disconnect).</p><p>This clause does not apply to casual Employees.</p><p><strong>95A.1</strong> General</p><p><strong>(a)</strong> The Right to Disconnect refers to an Employee’s right under the Act to be able to disengage from work and refrain from engaging in work-related communications, such as emails, telephone calls or other messages, while an Employee is off-duty, including during periods of approved leave or rostered days off.</p><p><strong>(b)</strong> The primary challenge to an Employee’s Right to Disconnect is out of hours contact to determine availability for additional shifts.</p><p><strong>95A.2</strong> Filling vacancies through the Supplementary Roster This Agreement makes provision for:</p><p><strong>(a)</strong> Availability arrangements via the supplementary rosters,</p><p><strong>(b)</strong> Change of roster allowance, and</p><p><strong>(c)</strong> On-call and recall arrangements. The Employer will consult the Supplementary Roster before reliance on mechanisms described at subclauses (b) or (c) above or otherwise contacting an Employee (including through text message or instant messaging applications (e.g. WhatsApp) to determine their availability for an additional shift or different shift.</p><p><strong>95A.3</strong> Employer Obligations to Support Right to Disconnect To support the Right of Employees to Disconnect, the Employer will:</p><p><strong>(a)</strong> Undertake a review of its arrangements for contacting Employees out of hours to determine availability, to ensure the system for contact is as efficient as possible, avoiding unnecessary contacts (such as multiple incidents of contact for the same shift) and prioritising use of the supplementary roster; and</p><p><strong>(b)</strong> Report the results of the review under subclause 95A.3(a) to the WIC and the status of supplementary roster arrangements.</p><p><strong>(c)</strong> The actions made under subclauses 95A.3(a) and (b) shall occur within the first six months of this Agreement commencing operation and shall be reported to the WIC.</p><p><strong>(d)</strong> The WIC will work cooperatively to address any identified instances of contact inconsistent with the clause during the life of this Agreement.</p><p><strong>95B.4</strong> Employee Right to Disconnect in relation to requests for additional or changed hours of work Employees are not required to read or respond to emails, messages or phone calls outside of their on-duty periods with respect to offers or requests for additional or changed hours of work unless:</p><p><strong>(a)</strong> the Employee has indicated availability for the relevant shift in accordance with <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/95-supplementary-roster.html">clause 95</a> (Supplementary Roster);</p><p><strong>(b)</strong> the Employee is in receipt of the on-call allowance for that period as set out in <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/91-oncall-recall-non-catt.html">clause 91</a> (On-call/Recall (non-CATT)) or 92 (CATT On-call/ Recall Allowances); or</p><p><strong>(c)</strong> the Employee has been directed by the Employer to perform overtime.</p><p>Plain language terms: after hours contact, out of hours, work-life boundary, no phone calls after work.</p>',20)])])}const d=t(s,[["render",a]]);export{g as __pageData,d as default};
